class Solution:
    def isLongPressedName(self, name: str, typed: str) -> bool:
        # brute-force: try all possible repetition counts
        from itertools import product
        groups = []
        i = 0
        while i < len(name):
            j = i
            while j < len(name) and name[j] == name[i]:
                j += 1
            groups.append((name[i], j - i))
            i = j
        def build(counts):
            return ''.join(c * cnt for c, cnt in zip([g[0] for g in groups], counts))
        min_counts = [g[1] for g in groups]
        # check if typed could be built by expanding each group's count
        # parse typed into runs
        typed_groups = []
        k = 0
        while k < len(typed):
            m = k
            while m < len(typed) and typed[m] == typed[k]:
                m += 1
            typed_groups.append((typed[k], m - k))
            k = m
        if len(typed_groups) != len(groups):
            return False
        for (nc, nmin), (tc, tcnt) in zip(groups, typed_groups):
            if nc != tc or tcnt < nmin:
                return False
        return True

